import json
with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                pkgs[key] = pkg['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, tfm, pkg_id = key
    bv = b.get(key, 'N/A')
    av = a.get(key, 'N/A')
    if bv != av:
        changes.append((proj, tfm, pkg_id, bv, av))
    else:
        unchanged.append((proj, tfm, pkg_id, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]:20s} {c[1]:10s} {c[2]:50s} {c[3]:10s} -> {c[4]}')
else:
    print('None')

print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')" 2>&1

